patch:
Index: sonnenschein/arch/i386/kernel/cpu/cpufreq/speedstep-smi.c
===================================================================
--- sonnenschein.orig/arch/i386/kernel/cpu/cpufreq/speedstep-smi.c
+++ sonnenschein/arch/i386/kernel/cpu/cpufreq/speedstep-smi.c
@@ -52,9 +52,9 @@ static struct cpufreq_frequency_table sp
 #define SET_SPEEDSTEP_STATE 2
 #define GET_SPEEDSTEP_FREQS 4

-/* how often shall the SMI call be tried if it failed, e.g. because
- * of DMA activity going on? */
-#define SMI_TRIES 5
+/* how often shall the SMI call be tried (it can easily fail, e.g. because
+ * of DMA activity going on) */
+#define SMI_TRIES 6

 #define dprintk(msg...) cpufreq_debug_printk(CPUFREQ_DEBUG_DRIVER, "speedstep-smi", msg)

@@ -161,7 +161,7 @@ static void speedstep_set_state (unsigne
 	unsigned int result = 0, command, new_state;
 	unsigned long flags;
 	unsigned int function=SET_SPEEDSTEP_STATE;
-	unsigned int retry = 0;
+	unsigned int try = 0;

 	if (state > 0x1)
 		return;
@@ -174,24 +174,22 @@ static void speedstep_set_state (unsigne
 	dprintk("trying to set frequency to state %u with command %x at port %x\n", state, command, smi_port);

 	do {
-		if (retry) {
-			dprintk("retry %u, previous result %u, waiting...\n", retry, result);
-			mdelay(retry * 50);
-		}
-		retry++;
+		dprintk("try %u, previous result %u, waiting...\n", try, result);
+		mdelay(try * 50);
+		try++;
 		__asm__ __volatile__(
 			"movl $0, %%edi\n"
 			"out %%al, (%%dx)\n"
 			: "=b" (new_state), "=D" (result)
 			: "a" (command), "b" (function), "c" (state), "d" (smi_port), "S" (0)
 			);
-	} while ((new_state != state) && (retry <= SMI_TRIES));
+	} while ((new_state != state) && (try <= SMI_TRIES));

 	/* enable IRQs */
 	local_irq_restore(flags);

 	if (new_state == state) {
-		dprintk("change to %u MHz succeeded after %u tries with result %u\n", (speedstep_freqs[new_state].frequency / 1000), retry, result);
+		dprintk("change to %u MHz succeeded after %u tries with result %u\n", (speedstep_freqs[new_state].frequency / 1000), try, result);
 	} else {
 		printk(KERN_ERR "cpufreq: change failed with new_state %u and result %u\n", new_state, result);
 	}
--- ../linux-source-2.6.15.orig/arch/i386/kernel/cpu/cpufreq/speedstep-smi.c	2006-01-03 05:21:10.000000000 +0200
+++ arch/i386/kernel/cpu/cpufreq/speedstep-smi.c	2006-01-21 23:13:06.000000000 +0200
@@ -70,7 +70,7 @@
 	command = (smi_sig & 0xffffff00) | (smi_cmd & 0xff);
 	magic = virt_to_phys(magic_data);

-	dprintk("trying to obtain ownership with command %x at port %x\n", command, smi_port);
+	printk("trying to obtain ownership with command %x at port %x\n", command, smi_port);

 	__asm__ __volatile__(
 		"out %%al, (%%dx)\n"
